1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Customer {
8	  yearsWithMHPCO: number;
9	  contractCount: number;
10	}
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	const BLOCK_PRICE_FOR_3_ALIKE = 60;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const ENCHANTMENT_SURCHARGE_MULTIPLIER = 0.3;
23	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
24	const FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER = 0.85;
25	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
26	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	
29	const roundToCents = (amount: number): number => Math.round(amount * 100) / 100;
30	
31	const PROCESSING_FEE = 5;
32	
33	const calculateItemCosts = (items: Item[]): number => {
34	  const nonCursedCountsByType: Record<string, number> = {};
35	  let cursedCost = 0;
36	  let enchantmentSurcharge = 0;
37	
38	  for (const item of items) {
39	    const itemBasePremium = BASE_PREMIUMS[item.type];
40	    if (item.cursed) {
41	      cursedCost += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
42	    } else {
43	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
44	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
45	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
46	      }
47	    }
48	  }
49	
50	  let nonCursedCost = 0;
51	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
52	    if (count === 3) {
53	      nonCursedCost += BLOCK_PRICE_FOR_3_ALIKE;
54	    } else {
55	      nonCursedCost += count * BASE_PREMIUMS[type];
56	    }
57	  }
58	
59	  return cursedCost + nonCursedCost + enchantmentSurcharge;
60	};
61	
62	export function generateQuote(items: Item[], customer: Customer): { basePremium: number; premium: number } {
63	  let basePremium = calculateItemCosts(items);
64	
65	  basePremium *= FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
66	
67	  if (customer.contractCount >= 1) {
68	    basePremium *= FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER;
69	  }
70	
71	  if (customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_MIN_YEARS) {
72	    basePremium *= LOYALTY_DISCOUNT_MULTIPLIER;
73	  }
74	
75	  const roundedBasePremium = roundToCents(basePremium);
76	  return { basePremium: roundedBasePremium, premium: roundedBasePremium + PROCESSING_FEE };
77	}
78	
79	export function processClaim(policy: unknown, incident: unknown): { payout: number; remainingCap: number } {
80	  return undefined as unknown as { payout: number; remainingCap: number };
81	}
